import { Client, Databases, ID, Query, Permission, Role } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
  .setProject('YOUR_PROJECT_ID'); // Replace with your project ID

const databases = new Databases(client);

async function setupTasks() {
  try {
    // 1. Create database
    const databaseId = 'tasksDB'; // Custom ID
    const database = await databases.create(databaseId, 'Tasks Database');

    // 2. Create 'tasks' collection
    const collectionId = 'tasks';
    const collection = await databases.createCollection(
      databaseId,
      collectionId,
      'Tasks',
      [
        Permission.read(Role.any()),
        Permission.write(Role.users()),
        Permission.read(Role.users()),
        Permission.update(Role.users()),
        Permission.delete(Role.users())
      ]
    );

    // 3. Create attributes
    // title: string
    await databases.createStringAttribute(databaseId, collectionId, 'title', 255, true);

    // completed: boolean
    await databases.createBoolAttribute(databaseId, collectionId, 'completed', true);

    // dueDate: datetime
    await databases.createDatetimeAttribute(databaseId, collectionId, 'dueDate', true);

    // Wait for attributes to be ready (Appwrite requires this)
    await new Promise(resolve => setTimeout(resolve, 1000));

    // 4. Create a document
    const task = {
      title: 'Sample Task',
      completed: false,
      dueDate: new Date().toISOString()
    };
    const document = await databases.createDocument(
      databaseId,
      collectionId,
      ID.unique(),
      task
    );

    console.log('Database, collection, attributes, and document created:', document);
  } catch (error) {
    console.error('Error:', error);
  }
}

setupTasks();
```

**Notes:**
- Replace `'YOUR_PROJECT_ID'` with your actual Appwrite project ID.
- Ensure your Appwrite project has database write permissions enabled for the client (e.g., via scopes or API key if using server-side).
- Attributes are created with `required: true`. Adjust as needed.
- Collection permissions allow any read, authenticated users to write/update/delete.
- Run this in a browser environment with the Appwrite SDK installed (`npm install appwrite`).
- Idempotency: Re-running may fail if resources exist; use `list*` queries to check first in production.

