import { Client } from 'appwrite';

const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your Appwrite endpoint
  .setProject('yourProjectId');                // Replace with your project ID

const DATABASE_ID = 'yourDatabaseId';         // Replace with your database ID
const COLLECTION_ID = 'yourCollectionId';     // Replace with your collection ID
const BUCKET_ID = 'yourBucketId';             // Replace with your storage bucket ID

// Subscribe to both document changes and file changes simultaneously
const unsubscribe = client.subscribe(
  [
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,  // Wildcard for all documents in collection
    `storage.buckets.${BUCKET_ID}.files`                                // Wildcard for all files in bucket
  ],
  (response) => {
    const event = response.events[0]; // Typically one event per payload

    // Handle document events (create/update/delete)
    if (event.startsWith(`databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents.`)) {
      const eventType = event.split('.').pop(); // Extracts 'create', 'update', or 'delete'
      const document = response.payload;        // Document data

      switch (eventType) {
        case 'create':
          console.log('📄 New document created:', document.$id, document);
          // Add your create handler logic here
          break;
        case 'update':
          console.log('📄 Document updated:', document.$id, document);
          // Add your update handler logic here
          break;
        case 'delete':
          console.log('📄 Document deleted:', document.$id);
          // Add your delete handler logic here (note: payload may be minimal)
          break;
      }
    }
    // Handle file events (create/update/delete)
    else if (event.startsWith(`storage.buckets.${BUCKET_ID}.files.`)) {
      const eventType = event.split('.').pop(); // Extracts 'create', 'update', or 'delete'
      const file = response.payload;            // File data

      switch (eventType) {
        case 'create':
          console.log('📁 File uploaded:', file.$id, file.name);
          // Add your file upload handler logic here
          break;
        case 'update':
          console.log('📁 File updated:', file.$id, file.name);
          // Add your file update handler logic here
          break;
        case 'delete':
          console.log('📁 File deleted:', file.$id);
          // Add your file delete handler logic here (note: payload may be minimal)
          break;
      }
    }
  }
);

console.log('✅ Subscribed to document changes and file uploads');

// To unsubscribe (e.g., on component unmount or page leave):
// unsubscribe();
```

This code uses the Appwrite Web SDK (v13+) to subscribe to realtime events on a specific database collection (documents) and storage bucket (files) simultaneously via wildcard channels. It differentiates event types by parsing the full event string from `response.events[0]` and handles create/update/delete distinctly for each service. Replace placeholders with your actual IDs. Ensure the client has necessary permissions (e.g., via API keys or sessions). Unsubscribe to avoid memory leaks.

```javascript
client.subscribe(
  [
    'database.[DATABASE_ID].collection.[COLLECTION_ID].document.*',
    'storage.[BUCKET_ID].file.*'
  ],
  (response) => {
    // Handle realtime event
  }
);
```

**Channel strings:**
- Database collection documents: `database.[DATABASE_ID].collection.[COLLECTION_ID].document.*`
- Storage bucket files: `storage.[BUCKET_ID].file.*`

Here is the complete code to implement Email/Password Signup and Login using the Appwrite Web SDK.

I have provided two versions:
1.  **Modern JavaScript (ES Modules):** Best for use with React, Vue, Svelte, or a bundler like Vite/Webpack.
2.  **HTML/CDN:** Best for quick testing in a simple `index.html` file without a build step.

### Prerequisites

First, install the Appwrite SDK via npm:

```bash
npm install appwrite
```

---

### 1. JavaScript Implementation (ES Modules)

This script sets up the client, handles the signup logic, and handles the login logic.

```javascript
import { Client, Account } from 'appwrite';

// 1. Setup the Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID'); // Your Project ID

const account = new Account(client);

// 2. Signup Function
const signup = async (email, password, name) => {
    try {
        // 'unique()' generates a random ID. 
        // You can also pass a specific string ID if you have one.
        const user = await account.create('unique()', email, password, name);

        console.log('Signup successful:', user);

        // Optional: Automatically log the user in after signup
        // return await login(email, password); 

        return user;
    } catch (error) {
        console.error('Signup failed:', error);
        throw error;
    }
};

// 3. Login (Create Session) Function
const login = async (email, password) => {
    try {
        const session = await account.createEmailSession(email, password);

        console.log('Login successful:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error);
        throw error;
    }
};

// Example Usage (Call these functions based on your form events)
// signup('user@example.com', 'password123', 'John Doe');
// login('user@example.com', 'password123');
```

