            try {
                status.innerText = "Signing up...";

                // Create Account
                await account.create('unique()', email, password, name);

                status.innerText = "Signup successful! Please log in.";
                // Optional: Clear fields
            } catch (error) {
                console.error(error);
                status.innerText = "Error: " + error.message;
            }
        }

