## 5. Complete Usage Example

```javascript
// Complete authentication example
class AuthService {
    constructor() {
        this.client = new Client()
            .setEndpoint('https://cloud.appwrite.io/v1')
            .setProject('YOUR_PROJECT_ID');

        this.account = new Account(this.client);
    }

    // Signup with email/password
    async signup(email, password, name = '') {
        try {
            const user = await this.account.create(
                'unique()',
                email,
                password,
                name
            );

            // Auto-login after signup
            await this.login(email, password);
            return user;

        } catch (error) {
            console.error('Signup error:', error);
            throw error;
        }
    }

    // Login with email/password
    async login(email, password) {
        try {
            await this.account.createEmailSession(email, password);
            return await this.getCurrentUser();
        } catch (error) {
            console.error('Login error:', error);
            throw error;
        }
    }

    // Get current logged-in user
    async getCurrentUser() {
        try {
            return await this.account.get();
        } catch (error) {
            console.error('Not authenticated:', error);
            return null;
        }
    }

    // Logout
    async logout() {
        try {
            await this.account.deleteSession('current');
            console.log('Logged out successfully');
        } catch (error) {
            console.error('Logout error:', error);
        }
    }

    // Check if user is logged in
    async isLoggedIn() {
        const user = await this.getCurrentUser();
        return user !== null;
    }
}

// Usage example
const auth = new AuthService();

// Signup
auth.signup('user@example.com', 'password123', 'John Doe')
    .then(user => console.log('Signed up:', user))
    .catch(error => console.error('Signup failed:', error));

// Login
auth.login('user@example.com', 'password123')
    .then(user => console.log('Logged in:', user))
    .catch(error => console.error('Login failed:', error));

// Check authentication status
auth.isLoggedIn().then(isLoggedIn => {
    console.log('Is logged in?', isLoggedIn);
});
```

