Here's a complete example using the Appwrite Web SDK to create a bucket, upload an image file, and generate a preview URL with proper permission configuration:

```javascript
import { Client, Storage, ID } from 'appwrite';

// Initialize the client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('YOUR_PROJECT_ID'); // Your project ID

const storage = new Storage(client);

// 1. Create a bucket with permissions
async function createBucket() {
    try {
        const bucket = await storage.createBucket(
            'uniqueBucketId', // Unique bucket ID
            'My Image Bucket', // Bucket name
            [
                'file.create', // Who can upload files
                'file.read',    // Who can read files
                'bucket.read'   // Who can read bucket details
            ],
            true, // Enabled
            100,  // Maximum file size in MB
            ['jpg', 'png', 'gif'], // Allowed file extensions
            'none', // No encryption
            false   // Don't scan files for viruses
        );

        console.log('Bucket created:', bucket);
        return bucket.$id;
    } catch (error) {
        // If bucket already exists, use existing bucket ID
        if (error.code === 409) {
            console.log('Bucket already exists');
            return 'uniqueBucketId';
        }
        throw error;
    }
}

// 2. Upload a file with permissions
async function uploadFile(bucketId, file) {
    try {
        const uploadedFile = await storage.createFile(
            bucketId,
            ID.unique(), // Generate unique file ID
            file,
            [
                'read("any")',    // Anyone can read (for public preview)
                'write("user:USER_ID")' // Replace USER_ID with specific user
            ]
        );

        console.log('File uploaded:', uploadedFile);
        return uploadedFile.$id;
    } catch (error) {
        console.error('Upload error:', error);
        throw error;
    }
}

// 3. Get preview URL for image
function getPreviewUrl(bucketId, fileId) {
    // For image preview with resize
    const previewUrl = storage.getFilePreview(
        bucketId,
        fileId,
        300, // Width
        300, // Height
        'top', // Gravity for cropping
        90,    // Quality (1-100)
        'webp' // Output format
    );

    return previewUrl;
}

// Example usage
async function main() {
    try {
        // Create or get bucket
        const bucketId = await createBucket();

        // Simulate file input (in real usage, get from file input)
        const fileInput = document.getElementById('fileInput');
        const file = fileInput.files[0];

        // Upload file
        const fileId = await uploadFile(bucketId, file);

        // Get preview URL
        const previewUrl = getPreviewUrl(bucketId, fileId);
        console.log('Preview URL:', previewUrl);

        // Display preview
        const img = document.createElement('img');
        img.src = previewUrl;
        document.body.appendChild(img);

    } catch (error) {
        console.error('Error:', error);
    }
}

// Alternative: Get file view URL (for original file)
function getFileViewUrl(bucketId, fileId) {
    return storage.getFileView(bucketId, fileId);
}

// Alternative: Get file download URL
function getFileDownloadUrl(bucketId, fileId) {
    return storage.getFileDownload(bucketId, fileId);
}
