As of the current stable version of Appwrite, there is **no native "Messaging" service** for push notifications. Appwrite does not directly manage push notification providers or device tokens within its core API services (like it does for Databases or Auth).

To implement push notifications, you must use **Appwrite Functions** to integrate with external providers. Here is how to set it up:

### 1. Supported Providers
Since you integrate via HTTP requests within a Function, you can use **any provider** with a REST API. The most common are:
*   **Firebase Cloud Messaging (FCM):** Standard for Android and Web.
*   **Apple Push Notification service (APNS):** Required for iOS.
*   **OneSignal / Pusher:** Aggregators that handle both FCM and APNS for you.

### 2. Setup Architecture
1.  **Device Registration:** Use your client app to send the device push token to an Appwrite **Database Collection** (e.g., `devices`) along with the `userId`.
2.  **Topic Subscription:** Create a collection (e.g., `topic_subscriptions`) to map `userId` or `deviceId` to specific topics (e.g., `news`, `alerts`).
3.  **Cloud Function:** Create an Appwrite Function (e.g., `send-push`) triggered manually or by a database event.

### 3. Sending to a Topic
To send a notification to a topic, you must query your database to find all subscribers, then loop through them to send the push via your external provider.

**Example Logic (Node.js Function):**
```javascript
import { Client, Databases } from 'node-appwrite';
import fetch from 'node-fetch';

export default async function({ req, res, log, error }) {
    const client = new Client()
        .setEndpoint(process.env.APPWRITE_ENDPOINT)
        .setProject(process.env.APPWRITE_PROJECT_ID)
        .setKey(process.env.APPWRITE_API_KEY); // Use API Key for server-side

    const databases = new Databases(client);

    // 1. Get topic name from request
    const { topic, message } = JSON.parse(req.body);

    // 2. Query subscribers from your DB collection
    const subscribers = await databases.listDocuments(
        process.env.DATABASE_ID,
        process.env.TOPICS_COLLECTION_ID,
        [Query.equal('topic', topic)]
    );

    // 3. Send push via external provider (e.g., FCM)
    for (const sub of subscribers.documents) {
        await fetch('https://fcm.googleapis.com/fcm/send', {
            method: 'POST',
            headers: {
                'Authorization': `key=${process.env.FCM_SERVER_KEY}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                to: sub.deviceToken,
                notification: { title: topic, body: message }
            })
        });
    }

    return res.json({ success: true });
}
```

### Summary
*   **Native Service:** None.
*   **Implementation:** Appwrite Functions + External API (FCM/APNS/OneSignal).
*   **Topics:** Managed via Appwrite Database Collections and queried within your Function.

# Appwrite Web SDK: Realtime Document & File Subscriptions

Here's a complete example demonstrating how to subscribe to realtime document changes and file uploads simultaneously using the Appwrite Web SDK, with distinct handling for each event type:

```javascript
import { Client, Databases, Storage, ID } from 'appwrite';

// Initialize Appwrite Client
const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')
  .setProject('YOUR_PROJECT_ID');

const databases = new Databases(client);
const storage = new Storage(client);

// Configuration
const DATABASE_ID = 'your_database_id';
const COLLECTION_ID = 'your_collection_id';
const BUCKET_ID = 'your_bucket_id';

// Track active subscriptions for cleanup
const subscriptions = [];

// Subscribe to Document Changes
function subscribeToDocuments() {
  const subscription = client.subscribe(
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
    (response) => {
      console.log('📄 Document Event:', response);

      switch (response.action) {
        case 'create':
          handleDocumentCreate(response.payload);
          break;
        case 'update':
          handleDocumentUpdate(response.payload);
          break;
        case 'delete':
          handleDocumentDelete(response.payload);
          break;
        default:
          console.log('Unknown document action:', response.action);
      }
    }
  );

  subscriptions.push(subscription);
  return subscription;
}

// Subscribe to File Uploads
function subscribeToFiles() {
  const subscription = client.subscribe(
    `buckets.${BUCKET_ID}.files`,
    (response) => {
      console.log('📁 File Event:', response);

      switch (response.action) {
        case 'create':
          handleFileUpload(response.payload);
          break;
        case 'delete':
          handleFileDelete(response.payload);
          break;
        default:
          console.log('Unknown file action:', response.action);
      }
    }
  );

  subscriptions.push(subscription);
  return subscription;
}

// Document Event Handlers
function handleDocumentCreate(payload) {
  console.log('✅ New document created:', payload.$id);
  // Update UI, notify users, etc.
  updateDocumentList(payload);
}

function handleDocumentUpdate(payload) {
  console.log('🔄 Document updated:', payload.$id);
  // Refresh specific document in UI
  refreshDocument(payload.$id);
}

function handleDocumentDelete(payload) {
  console.log('🗑️ Document deleted:', payload.$id);
  // Remove from UI
  removeDocumentFromUI(payload.$id);
}

// File Event Handlers
function handleFileUpload(payload) {
  console.log('⬆️ New file uploaded:', payload.$id);
  console.log('File name:', payload.name);
  console.log('File size:', payload.sizeOriginal);

  // Get file preview URL
  const fileUrl = storage.getFilePreview(BUCKET_ID, payload.$id);
  displayFileInGallery(payload, fileUrl);
}

function handleFileDelete(payload) {
  console.log('🗑️ File deleted:', payload.$id);
  // Remove from gallery
  removeFileFromGallery(payload.$id);
}

// UI Helper Functions (implement based on your framework)
function updateDocumentList(document) {
  // Add document to your UI list
}

function refreshDocument(documentId) {
  // Fetch and update specific document
}

function removeDocumentFromUI(documentId) {
  // Remove document from UI
}

function displayFileInGallery(file, url) {
  // Display file in your gallery UI
}

function removeFileFromGallery(fileId) {
  // Remove file from gallery UI
}

// Initialize all subscriptions
function initializeRealtime() {
  try {
    subscribeToDocuments();
    subscribeToFiles();
    console.log('✅ Realtime subscriptions active');
  } catch (error) {
    console.error('❌ Failed to initialize realtime:', error);
  }
}

// Cleanup subscriptions (call on component unmount/logout)
function cleanupSubscriptions() {
  subscriptions.forEach(subscription => {
    subscription();
  });
  subscriptions.length = 0;
  console.log('🧹 Realtime subscriptions cleaned up');
}

// Example: Upload a file to trigger the file event
async function uploadFile(file) {
  try {
    const result = await storage.createFile(BUCKET_ID, ID.unique(), file);
    console.log('File uploaded successfully:', result.$id);
  } catch (error) {
    console.error('File upload failed:', error);
  }
}

// Example: Create a document to trigger the document event
async function createDocument(data) {
  try {
    const result = await databases.createDocument(
      DATABASE_ID,
      COLLECTION_ID,
      ID.unique(),
      data
    );
    console.log('Document created successfully:', result.$id);
  } catch (error) {
    console.error('Document creation failed:', error);
  }
}

// Initialize when app loads
initializeRealtime();

// Cleanup when app unloads (for vanilla JS)
window.addEventListener('beforeunload', cleanupSubscriptions);

// For React/Vue/Angular, call cleanupSubscriptions() in component unmount hooks
```

