 Here's an Appwrite Function for Node.js that handles JSON input and returns a personalized greeting:

```javascript
export default async ({ req, res, log, error }) => {
  try {
    // Parse the JSON body (req.body is a string in Appwrite Functions)
    const payload = JSON.parse(req.body);
    const { name } = payload;

    // Validate the name field
    if (!name || typeof name !== 'string') {
      return res.json(
        { success: false, message: 'Missing or invalid "name" field' }, 
        400
      );
    }

    // Log for debugging (visible in Appwrite Console logs)
    log(`Generating greeting for: ${name}`);

    // Return successful response
    return res.json({
      success: true,
      greeting: `Hello, ${name}! 👋`,
      timestamp: new Date().toISOString()
    });

  } catch (err) {
    // Log error details
    error(`Function error: ${err.message}`);

    // Return error response
    return res.json(
      { success: false, message: 'Invalid JSON body provided' }, 
      400
    );
  }
};
```

**Key points:**
- **Signature**: Uses the standard Appwrite context object with `req`, `res`, `log`, and `error`
- **Body parsing**: `req.body` is a string, so `JSON.parse()` is required
- **Response**: `res.json()` automatically sets `Content-Type: application/json`
- **Status codes**: Second parameter sets HTTP status (200 default, 400 for errors)
- **Logging**: `log()` and `error()` write to the Appwrite Console execution logs

**Runtime compatibility:** Works with Node.js 16.0, 18.0, and 20.0 runtimes in Appwrite.

 Here's a complete example using the Appwrite Web SDK (v14+):

```javascript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Initialize client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID');

const storage = new Storage(client);

/**
 * 1. Create a bucket with permissions
 */
async function createImageBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),           // Bucket ID
            'Image Uploads',       // Bucket name
            [
                Permission.read(Role.any()),      // Public read access
                Permission.create(Role.users()),  // Auth users can upload
                Permission.update(Role.users()),  // Auth users can update
                Permission.delete(Role.users())   // Auth users can delete
            ],
            false,                 // fileSecurity (false = bucket-level permissions)
            true,                  // enabled
            10485760,              // 10MB max file size (bytes)
            ['jpg', 'jpeg', 'png', 'gif', 'webp'] // Allowed extensions
        );

        console.log('Bucket created:', bucket.$id);
        return bucket.$id;
    } catch (error) {
        console.error('Error creating bucket:', error);
        throw error;
    }
}

/**
 * 2. Upload a file
 */
async function uploadImage(bucketId, fileInput) {
    try {
        const file = fileInput.files[0];
        if (!file) throw new Error('No file selected');

        const result = await storage.createFile(
            bucketId,
            ID.unique(),           // File ID
            file,                  // File object from input
            [],                    // Permissions (empty = use bucket-level)
            (progress) => {        // Optional progress callback
                console.log(`Upload: ${progress.progress}%`);
            }
        );

        console.log('File uploaded:', result.$id);
        return result;
    } catch (error) {
        console.error('Upload error:', error);
        throw error;
    }
}

/**
 * 3. Get image preview URL
 */
function getImagePreview(bucketId, fileId) {
    // Returns a URL string with transformations applied
    const url = storage.getFilePreview(
        bucketId,
        fileId,
        800,                   // width
        600,                   // height
        'center',              // gravity (center/top/bottom/left/right)
        90,                    // quality (0-100)
        0,                     // borderWidth
        '',                    // borderColor (hex without #)
        0,                     // borderRadius
        100,                   // opacity
        0,                     // rotation (degrees)
        'FFFFFF',              // background color
        'jpg'                  // output format (jpg/png/webp)
    );

    return url;
}

// Usage Example
async function handleUpload(fileInputElement) {
    try {
        // Create bucket (or use existing ID)
        const bucketId = await createImageBucket();

        // Upload file
        const uploadedFile = await uploadImage(bucketId, fileInputElement);

        // Get preview URL
        const previewUrl = getImagePreview(bucketId, uploadedFile.$id);

        console.log('Preview URL:', previewUrl);

        // Display in HTML
        const img = document.createElement('img');
        img.src = previewUrl;
        document.body.appendChild(img);

        return { bucketId, fileId: uploadedFile.$id, previewUrl };

    } catch (error) {
        console.error('Process failed:', error);
    }
}

// HTML: <input type="file" id="fileInput" accept="image/*" />
// document.getElementById('fileInput').addEventListener('change', (e) => {
//     handleUpload(e.target);
// });
```

**Key Points:**

- **Permissions**: `Role.any()` allows public access to previews without authentication. Use `Role.users()` to restrict to authenticated users only.
- **Bucket vs File Permissions**: Set `fileSecurity` to `false` for bucket-level permissions (simpler), or `true` to set permissions per individual file.
- **Preview URL**: `getFilePreview()` returns a constructed URL string immediately—no async/await needed. The image transformations happen server-side when the URL is accessed.
- **Requirements**: The bucket must have read permissions, and the file must be an image format supported by Appwrite (JPEG, PNG, GIF, WebP).

