const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function waitForAttributes(databaseId, collectionId, keys) {
  while (true) {
    const { attributes } = await databases.listAttributes(databaseId, collectionId);

    const ready = keys.every((key) =>
      attributes.some((a) => a.key === key && a.status === "available")
    );

    const failed = attributes.find(
      (a) => keys.includes(a.key) && a.status === "failed"
    );
    if (failed) throw new Error(`Attribute "${failed.key}" failed to create`);

    if (ready) return;
    await sleep(500);
  }
}

async function createSchemaAndInsertTask() {
