    "title",
    255,
    true
  );
  await databases.createBooleanAttribute(
    databaseId,
    collectionId,
    "completed",
    true,
    false
  );
  await databases.createDatetimeAttribute(
    databaseId,
    collectionId,
    "dueDate",
    true
  );

  // Wait until attributes are ready before inserting documents
  await waitForAttributes(databaseId, collectionId, [
    "title",
    "completed",
    "dueDate",
  ]);

  // 4) Insert a document
  const task = await databases.createDocument(
    databaseId,
    collectionId,
    ID.unique(),
    {
      title: "Finish Appwrite setup",
      completed: false,
      dueDate: new Date("2026-04-01T12:00:00Z").toISOString(),
    }
  );

  console.log("Created task document:", task);
}

createSchemaAndInsertTask().catch(console.error);
