```js
// npm i appwrite
import { Client, Account, Storage, ID, Permission, Role } from "appwrite";

// Assumes the user already has an authenticated session (cookie/JWT)
const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const account = new Account(client);
const storage = new Storage(client);

const BUCKET_ID = "images";

// 1) Create bucket (run once)
async function ensureBucket() {
  try {
    await storage.createBucket(
      BUCKET_ID,
      "Images",
      [
        Permission.read(Role.any()),              // anyone can read (preview/download)
        Permission.create(Role.users()),          // logged-in users can upload
        Permission.update(Role.team("<ADMIN_TEAM_ID>")),
        Permission.delete(Role.team("<ADMIN_TEAM_ID>")),
      ],
      true // fileSecurity enabled -> file-level permissions can be set on upload
    );
    console.log("Bucket created");
  } catch (err) {
    if (err.code === 409) {
      console.log("Bucket already exists");
    } else {
      throw err;
    }
  }
}

// 2) Upload image and return preview URL
async function uploadImageAndGetPreview(file) {
  const me = await account.get();

  const uploaded = await storage.createFile(
    BUCKET_ID,
    ID.unique(),
    file, // File from <input type="file" />
    [
      Permission.read(Role.any()),          // public preview URL
      Permission.update(Role.user(me.$id)), // only owner can modify/delete this file
      Permission.delete(Role.user(me.$id)),
    ]
  );

  const previewUrl = storage.getFilePreview(
    BUCKET_ID,
    uploaded.$id,
    800,   // width
    800,   // height
    "center",
    80     // quality
  );

  return previewUrl.toString?.() ?? previewUrl;
}

// Example usage with an <input id="imageInput" type="file" accept="image/*" />
document.getElementById("imageInput").addEventListener("change", async (e) => {
  const file = e.target.files?.[0];
  if (!file) return;

  await ensureBucket();
  const url = await uploadImageAndGetPreview(file);

  console.log("Preview URL:", url);
  // e.g. document.getElementById("previewImg").src = url;
});
```

**Important:** `createBucket` is a privileged action. In production, it’s best to run bucket creation in a trusted backend/Appwrite Function (Server SDK), then use Web SDK for upload + preview in the browser.

```js
import { Client } from "appwrite";

const client = new Client()
  .setEndpoint("<APPWRITE_ENDPOINT>") // e.g. https://<REGION>.cloud.appwrite.io/v1
  .setProject("<PROJECT_ID>");

const DATABASE_ID = "<DATABASE_ID>";
const COLLECTION_ID = "<COLLECTION_ID>";
const BUCKET_ID = "<BUCKET_ID>";

// One realtime subscription, multiple channels
const unsubscribe = client.subscribe(
  [
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
    `buckets.${BUCKET_ID}.files`,
  ],
  (message) => {
    const { events, payload } = message;

    const isDocEvent = events.some((e) =>
      e.startsWith(`databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`)
    );
    const isFileEvent = events.some((e) =>
      e.startsWith(`buckets.${BUCKET_ID}.files`)
    );

    const isCreate = events.some((e) => e.endsWith(".create"));
    const isUpdate = events.some((e) => e.endsWith(".update"));
    const isDelete = events.some((e) => e.endsWith(".delete"));

    if (isDocEvent) {
      if (isCreate) {
        console.log("📄 Document created:", payload);
      } else if (isUpdate) {
        console.log("✏️ Document updated:", payload);
      } else if (isDelete) {
        console.log("🗑️ Document deleted:", payload.$id);
      }
      return;
    }

    if (isFileEvent) {
      // File upload completion comes through as ".create"
      if (isCreate) {
        console.log("⬆️ File uploaded:", payload.name, payload.$id);
      } else if (isDelete) {
        console.log("🗑️ File deleted:", payload.$id);
      }
    }
  }
);

// Call when you want to stop listening
// unsubscribe();
```

Note: Realtime events are only delivered if the current user/session has **read** permission on those documents/files.

