// logIn('user@example.com', 'securepassword123');
```

### Key details:
* **`ID.unique()`**: Appwrite requires a unique ID when creating a user. The `ID` utility class handles this safely.
* **`createEmailPasswordSession`**: This method creates a secure session cookie in the browser. Subsequent requests to Appwrite will automatically include this cookie to authenticate the user. *(Note: In older SDK versions < v13, this method was called `createEmailSession`)*.

Here is the complete code to achieve this using the Appwrite Web SDK. 

Before running the code, ensure you have installed the SDK:
```bash
npm install appwrite
```

### JavaScript / TypeScript Implementation

```javascript
import { Client, Databases, ID } from 'appwrite';

// 1. Initialize the Appwrite Client and Databases service
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('<YOUR_PROJECT_ID>');            // Replace with your project ID

const databases = new Databases(client);

async function setupDatabaseAndInsertDocument() {
    try {
        // 2. Create a Database
        console.log('Creating database...');
        const database = await databases.create(ID.unique(), 'Task Manager DB');
        const dbId = database.$id;

        // 3. Create a Collection
        console.log('Creating collection...');
        const collection = await databases.createCollection(dbId, ID.unique(), 'Tasks');
        const colId = collection.$id;

        // 4. Create Attributes
        console.log('Creating attributes...');
        // String: key='title', size=255, required=true
        await databases.createStringAttribute(dbId, colId, 'title', 255, true);

        // Boolean: key='completed', required=false, default=false
        await databases.createBooleanAttribute(dbId, colId, 'completed', false, false);

        // Datetime: key='dueDate', required=false
        await databases.createDatetimeAttribute(dbId, colId, 'dueDate', false);

        // 5. Wait for attributes to be created
        // IMPORTANT: Attribute creation is asynchronous in Appwrite. 
        // We must wait a moment before inserting documents to avoid a "missing attribute" error.
        console.log('Waiting for attributes to build...');
        await new Promise(resolve => setTimeout(resolve, 3000)); 

        // 6. Insert a Document
        console.log('Inserting document...');
        const document = await databases.createDocument(
            dbId, 
            colId, 
            ID.unique(), 
            {
                title: 'Complete Appwrite integration',
                completed: false,
                dueDate: new Date(Date.now() + 86400000).toISOString() // Tomorrow
            }
        );

        console.log('Success! Document created:', document);

    } catch (error) {
        console.error('Appwrite Error:', error);
    }
}

setupDatabaseAndInsertDocument();
```

### Key Concepts to Note:
1. **`ID.unique()`**: Appwrite provides this helper to automatically generate unique, valid IDs for databases, collections, and documents.
2. **Asynchronous Attributes**: Creating attributes triggers a background worker in Appwrite. You **must** wait for the attributes' status to change to `available` before inserting documents. In production, instead of a hardcoded `setTimeout`, it is best practice to poll the `databases.listAttributes(dbId, colId)` endpoint until all attributes have `status === 'available'`.
3. **Datetime Format**: Appwrite expects Datetime attributes to be formatted as ISO 8601 strings (e.g., `YYYY-MM-DDTHH:mm:ss.SSSZ`), which is natively handled by JavaScript's `Date.toISOString()`.

In Appwrite, you query documents using the `databases.listDocuments()` method by passing an array of methods from the `Query` class. The `Query` class acts as a helper to build formatted query strings for filtering, sorting, and paginating your data.

Here is a breakdown of how to use the `Query` class, assuming you have already initialized your Appwrite Web SDK:

```javascript
import { Client, Databases, Query } from "appwrite";

const client = new Client().setEndpoint('YOUR_ENDPOINT').setProject('YOUR_PROJECT_ID');
const databases = new Databases(client);
```

### 1. Filtering
Filtering allows you to find documents that match specific criteria. Appwrite supports various operators like `equal`, `notEqual`, `lessThan`, `greaterThan`, `search`, and `contains`.

```javascript
const filteredDocs = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.equal('status', 'published'),
        Query.greaterThan('views', 100),
        Query.search('title', 'Appwrite') // Requires a full-text index on 'title'
    ]
);
```

### 2. Sorting
You can sort your results by specific attributes in ascending or descending order using `orderAsc` and `orderDesc`. You can pass multiple sorting queries to act as tie-breakers.

```javascript
const sortedDocs = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.orderDesc('createdAt'),
        Query.orderAsc('title')
    ]
);
```

### 3. Limiting
By default, Appwrite returns 25 documents per request. You can change this using `Query.limit()`. The maximum limit is typically 5,000.

```javascript
const limitedDocs = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.limit(10) // Returns only 10 documents
    ]
);
```

### 4. Pagination
Appwrite supports two types of pagination: **Offset** and **Cursor**.

**Offset Pagination:** Uses `Query.offset()` to skip a specific number of documents. It is easy to implement but can become slow with very large datasets.
```javascript
const pageTwo = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.limit(10),
        Query.offset(10) // Skips the first 10 documents
    ]
);
```

**Cursor Pagination:** Uses `Query.cursorAfter()` or `Query.cursorBefore()` passing a Document ID. This is highly performant and recommended for large datasets or infinite scrolling.
```javascript
const nextBatch = await databases.listDocuments(
    'DATABASE_ID',
    'COLLECTION_ID',
    [
        Query.limit(10),
        Query.cursorAfter('64a1b2c3d4e5f6g7h8i9') // The ID of the last document from the previous request
    ]
);
```

### Combined Example
Here is how you combine all of these concepts into a single, powerful query:

```javascript
async function fetchArticles(lastDocumentId = null) {
    const queries = [
        Query.equal('category', 'technology'),
        Query.greaterThanEqual('publishedYear', 2023),
        Query.orderDesc('views'),
        Query.limit(20)
    ];

    // Add cursor pagination if a document ID is provided
    if (lastDocumentId) {
        queries.push(Query.cursorAfter(lastDocumentId));
    }

    try {
        const response = await databases.listDocuments(
            'DATABASE_ID',
            'COLLECTION_ID',
            queries
        );
        console.log(response.documents);
    } catch (error) {
        console.error("Failed to fetch documents:", error);
    }
}
```

**💡 Expert Tip:** To use any attribute inside a `Query` (whether for filtering or sorting), you **must** create an Index for that attribute in your Appwrite Collection settings. If you don't, Appwrite will throw an index-missing error.

To achieve this in Appwrite, you need to pass an array of `Query` methods to the `listDocuments` endpoint. 

Here is how you combine the `greaterThan`, `orderDesc`, and `limit` queries:

### JavaScript / Web SDK Example

```javascript
import { Client, Databases, Query } from "appwrite";

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>');

const databases = new Databases(client);

async function fetchDocuments() {
    try {
        const response = await databases.listDocuments(
            '<DATABASE_ID>',
            '<COLLECTION_ID>',
            [
                // 1. Filter where the numeric field is greater than 100
                Query.greaterThan('yourNumericField', 100),

                // 2. Sort by the same field in descending order
                Query.orderDesc('yourNumericField'),

                // 3. Limit the results to a maximum of 20
                Query.limit(20)
            ]
        );

        console.log(response.documents);
    } catch (error) {
        console.error(error);
    }
}
```

### Breakdown of the Queries used:
* **`Query.greaterThan('field', value)`**: Filters the collection to only include documents where the specified attribute is strictly greater than the provided value.
* **`Query.orderDesc('field')`**: Sorts the returned documents from highest to lowest based on the specified attribute.
* **`Query.limit(value)`**: Restricts the payload to return no more than the specified number of documents (Appwrite's default limit is 25, maximum is 100). 

*Note: Ensure that you have created an **Index** on `yourNumericField` in your Appwrite collection settings, otherwise the query will fail.*

Here is the Appwrite Function in Node.js. 

Appwrite uses a specific function signature that provides a context object containing `req` (request), `res` (response), `log`, and `error` methods.

```javascript
export default async ({ req, res, log, error }) => {
  // Set a default name
  let name = "World";

  // Check if the request has a body
  if (req.body) {
    try {
      // Parse the body (Appwrite passes req.body as a string or object depending on the invocation)
      const payload = typeof req.body === 'string' ? JSON.parse(req.body) : req.body;

      // Extract the name if it exists
      if (payload.name) {
        name = payload.name;
      }
    } catch (err) {
      // Log the error to the Appwrite console
      error(`Failed to parse JSON: ${err.message}`);

      // Return a 400 Bad Request response
      return res.json({ success: false, message: "Invalid JSON body" }, 400);
    }
  }

  const greeting = `Hello, ${name}!`;

  // Log the successful execution
  log(`Greeting generated for: ${name}`);

  // Return the personalized greeting as a JSON response
  return res.json({
    success: true,
    message: greeting
  });
};
```

### Key Concepts Used:
* **`req.body`**: Contains the payload sent to the function. We check if it's a string and parse it safely using `JSON.parse()`.
* **`res.json(data, statusCode)`**: The standard way to return a JSON response in Appwrite. The default status code is `200`.
* **`log()` & `error()`**: Appwrite's built-in logging methods. These logs will appear in your Appwrite Console under the function's "Executions" tab, which is highly recommended for debugging.
* **ES Modules**: Appwrite Node.js functions use ES modules, which is why the function starts with `export default async`.

### How to test this:
When executing this function via the Appwrite Server SDK, Client SDK, or REST API, pass a JSON string as the body:

```json
{
  "name": "Alice"
}
```
**Response:**
```json
{
  "success": true,
  "message": "Hello, Alice!"
}
```

In Appwrite, **creating a bucket is an admin-level action**. For security reasons, the Web SDK (client-side) does not have the `createBucket` method. Buckets must be created using the Appwrite Console or a Server SDK (like Node.js) using an API key. 

Below is the complete workflow: how to create the bucket using the **Server SDK (Node.js)**, followed by how to upload a file and get a preview using the **Web SDK**.

### 1. Create a Bucket (Server SDK - Node.js)
You need an API key with the `buckets.write` scope to create a bucket. Here, we configure permissions so anyone can read the files, but only authenticated users can upload.

```javascript
import { Client, Storage, ID, Permission, Role } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>')
    .setKey('<YOUR_API_KEY>');

const storage = new Storage(client);

async function setupBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),
            'Image Uploads',
            [
                Permission.read(Role.any()),       // Anyone can view files
                Permission.create(Role.users()),   // Only logged-in users can upload
                Permission.update(Role.users()),
                Permission.delete(Role.users())
            ],
            false, // fileSecurity: false means bucket permissions apply to all files
            true,  // enabled
            5242880, // maximumFileSize (e.g., 5MB)
            ['jpg', 'png', 'jpeg', 'webp'] // allowedFileExtensions
        );
        console.log('Bucket Created:', bucket.$id);
        return bucket.$id;
    } catch (error) {
        console.error('Error creating bucket:', error);
    }
}
```

### 2. Upload File & Get Preview (Web SDK)
Once the bucket is created, use the Web SDK in your frontend to upload the image and generate a preview URL. We will also apply file-level permissions so only the specific user who uploaded it can delete or update it.

```javascript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>');

const storage = new Storage(client);

async function uploadAndPreviewImage(bucketId, fileElement, currentUserId) {
    try {
        // 1. Get the file from an HTML <input type="file" id="uploader">
        const file = fileElement.files[0];
        if (!file) throw new Error("No file selected");

        // 2. Upload the file with specific permissions
        const uploadedFile = await storage.createFile(
            bucketId,
            ID.unique(),
            file,
            [
                Permission.read(Role.any()),                  // Anyone can view this file
                Permission.update(Role.user(currentUserId)),  // Only the uploader can update
                Permission.delete(Role.user(currentUserId))   // Only the uploader can delete
            ]
        );

        console.log('File Uploaded:', uploadedFile.$id);

        // 3. Get the Image Preview URL (cropped to 800x600)
        const previewUrl = storage.getFilePreview(
            bucketId,
            uploadedFile.$id,
            800, // width
            600  // height
        );

        // getFilePreview returns a URL object. Use .href to get the string URL.
        console.log('Preview URL:', previewUrl.href);

        return previewUrl.href;

    } catch (error) {
        console.error('Error uploading file:', error);
    }
}

// Usage example:
// const fileInput = document.getElementById('uploader');
// uploadAndPreviewImage('<YOUR_BUCKET_ID>', fileInput, '<LOGGED_IN_USER_ID>');
```

### Key Takeaways:
* **`Permission` & `Role` helpers:** Use these to easily generate the correct permission strings (e.g., `Role.any()`, `Role.users()`, `Role.user('id')`).
* **File Security:** If you set `fileSecurity` to `true` when creating the bucket, file-level permissions will override bucket-level permissions. If `false`, users need *both* bucket and file permissions to access the file.
* **Synchronous Preview:** `getFilePreview` is synchronous and doesn't require an `await`. It instantly constructs and returns the URL object based on your parameters.

To send a push notification to all users subscribed to a topic, you will use the **Appwrite Messaging** service. 

Here is the breakdown of what must be configured first and the steps to send the notification.

### What Must Be Configured First (Prerequisites)

Before you can send a push notification, the following architecture must be set up:

1. **Configure a Provider:** In the Appwrite Console, navigate to **Messaging > Providers** and set up a push notification provider (e.g., FCM for Android/Web, or APNs for iOS) by providing your server keys/certificates.
2. **Create a Topic:** In the Console under **Messaging > Topics**, create a new topic (e.g., `announcements`) and note its `topicId`.
3. **Register Device Targets:** On the client side, retrieve the device's push token (via Firebase or Apple SDKs) and register it to the authenticated user using the Client SDK:
   ```javascript
   // Client-side example
   account.createPushTarget(ID.unique(), '<DEVICE_TOKEN>', '<PROVIDER_ID>');
   ```
4. **Subscribe Users to the Topic:** Add the user's target to the topic. This is typically done via the Server SDK or Console:
   ```javascript
   // Server-side example
   messaging.createSubscriber('<TOPIC_ID>', ID.unique(), '<TARGET_ID>');
   ```

---

### Steps to Send the Push Notification

Because sending push notifications is a privileged action, it must be done via the **Appwrite Console** or a **Server SDK** using an API key with the `messages.write` scope.

#### Option A: Via the Appwrite Console
1. Go to your Appwrite project and navigate to **Messaging**.
2. Click **Create Message** and select **Push Notification**.
3. Fill in the **Title** and **Body** of your message.
4. Under the **Targets** section, select **Topics** and choose the topic you created.
5. Click **Send** (or schedule it for later).

#### Option B: Via the Server SDK (Node.js Example)
1. Initialize the Appwrite Server SDK with your Project ID and API Key.
2. Use the `createPush` method on the Messaging service, passing the `topicId` in the `topics` array.

```javascript
const sdk = require('node-appwrite');

// 1. Initialize the Server Client
const client = new sdk.Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('<PROJECT_ID>')
    .setKey('<API_KEY>'); // Must have 'messages.write' scope

const messaging = new sdk.Messaging(client);

// 2. Send the Push Notification
async function sendTopicPush() {
    try {
        const response = await messaging.createPush(
            sdk.ID.unique(),               // messageId
            'New Feature Alert!',          // title
            'Check out the new update.',   // body
            ['<TOPIC_ID>']                 // topics array
        );
        console.log('Message sent successfully:', response);
    } catch (error) {
        console.error('Error sending message:', error);
    }
}

sendTopicPush();
```

*(Note: You can also pass optional parameters to `createPush` such as custom `data` payloads, `action` links, `icon`, `sound`, and `badge` counts depending on your app's needs).*

Here is how you can subscribe to multiple channels simultaneously and route the logic based on the event type using the Appwrite Web SDK.

You can pass an array of channels to the `client.subscribe()` method. Inside the callback, you can inspect the `response.events` array to determine whether the event originated from the Database or Storage service.

```javascript
import { Client } from 'appwrite';

// 1. Initialize the Appwrite Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('YOUR_PROJECT_ID');              // Replace with your project ID

const DATABASE_ID = 'YOUR_DATABASE_ID';
const COLLECTION_ID = 'YOUR_COLLECTION_ID';
const BUCKET_ID = 'YOUR_BUCKET_ID';

// 2. Define the channels you want to listen to
const channels = [
    `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
    `buckets.${BUCKET_ID}.files`
];

// 3. Subscribe to the channels
const unsubscribe = client.subscribe(channels, (response) => {

    // Appwrite returns an array of events for every realtime update
    const events = response.events;
    const payload = response.payload;

    // 4. Handle Document Events
    if (events.some(event => event.startsWith('databases.'))) {
        console.log('📄 Document Event Received');

        if (events.some(event => event.includes('.create'))) {
            console.log('New document created:', payload);
        } else if (events.some(event => event.includes('.update'))) {
            console.log('Document updated:', payload);
        } else if (events.some(event => event.includes('.delete'))) {
            console.log('Document deleted:', payload);
        }
    }

    // 5. Handle File Upload/Storage Events
    if (events.some(event => event.startsWith('buckets.'))) {
        console.log('📁 Storage Event Received');

        if (events.some(event => event.includes('.create'))) {
            console.log('New file uploaded:', payload);
        } else if (events.some(event => event.includes('.update'))) {
            console.log('File metadata updated:', payload);
        } else if (events.some(event => event.includes('.delete'))) {
            console.log('File deleted:', payload);
        }
    }
});

// Call unsubscribe() when you want to close the realtime connection (e.g., component unmount)
// unsubscribe();
```

### Key Concepts:
* **Array of Channels:** Passing `[channel1, channel2]` creates a single WebSocket connection for multiple subscriptions, which is highly efficient.
* **`response.events`:** This is an array of strings detailing exactly what happened (e.g., `databases.[id].collections.[id].documents.[id].create`). Using `.some()` and `.startsWith()` is the safest way to parse these strings.
* **`response.payload`:** Contains the actual JSON object of the document or file that was modified.

Here is the single `client.subscribe()` call listening to both channels:

```javascript
client.subscribe([
    'databases.[DATABASE_ID].collections.[COLLECTION_ID].documents',
    'buckets.[BUCKET_ID].files'
], response => {
    console.log('Realtime event received:', response);
});
```

### The Exact Channel Strings:
1. **Database Collection:** `'databases.[DATABASE_ID].collections.[COLLECTION_ID].documents'`
2. **Storage Bucket:** `'buckets.[BUCKET_ID].files'`

*(Note: Replace `[DATABASE_ID]`, `[COLLECTION_ID]`, and `[BUCKET_ID]` with your actual Appwrite resource IDs).*

Here’s a minimal Appwrite Web SDK example for email/password signup and login.

### 1) Install the SDK

```bash
npm install appwrite
```

### 2) Set up Appwrite and auth functions

```js
// appwrite-auth.js
import { Client, Account, ID } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1") // Your Appwrite endpoint
  .setProject("<PROJECT_ID>"); // Your project ID

const account = new Account(client);

// Sign up: create account, then create a session
export async function signUp(email, password, name = "") {
  const user = await account.create(
    ID.unique(),
    email,
    password,
    name
  );

  const session = await account.createEmailPasswordSession(email, password);

  return { user, session };
}

// Log in: create a session with email/password
export async function login(email, password) {
  return await account.createEmailPasswordSession(email, password);
}

// Optional: get the currently logged-in user
export async function getCurrentUser() {
  return await account.get();
}

// Optional: log out the current session
export async function logout() {
  return await account.deleteSession("current");
}
```

### 3) Example usage

```js
import { signUp, login, getCurrentUser, logout } from "./appwrite-auth.js";

async function run() {
  try {
    // Create account + session
    const { user, session } = await signUp(
      "jane@example.com",
      "supersecret123",
      "Jane Doe"
    );

    console.log("Signed up:", user);
    console.log("Session created:", session);

    // Or login separately
    // const session = await login("jane@example.com", "supersecret123");
    // console.log("Logged in:", session);

    const currentUser = await getCurrentUser();
    console.log("Current user:", currentUser);

    // await logout();
  } catch (error) {
    console.error("Auth error:", error);
  }
}

run();
```

### Notes
- Replace `<REGION>` and `<PROJECT_ID>` with your Appwrite values.
- Add your frontend URL in **Appwrite Console → Platforms**.
- `createEmailPasswordSession()` creates the login session for the browser automatically.

