```

```js
client.subscribe(
  [
    `databases.${databaseId}.collections.${collectionId}.documents`,
    `buckets.${bucketId}.files`,
  ],
  (response) => {
    console.log(response);
  }
);
```

Exact channel strings:

- Database collection documents: `databases.{databaseId}.collections.{collectionId}.documents`
- Storage bucket files: `buckets.{bucketId}.files`

You can subscribe to both channels in one Web SDK `subscribe()` call and branch by event type.

```js
import { Client } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const databaseId = "<DATABASE_ID>";
const collectionId = "<COLLECTION_ID>";
const bucketId = "<BUCKET_ID>";

const unsubscribe = client.subscribe(
  [
    `databases.${databaseId}.collections.${collectionId}.documents`,
    `buckets.${bucketId}.files`,
  ],
  ({ events, payload }) => {
    // Document create/update/delete
    const documentEvent = events.find((event) =>
      event.startsWith(
        `databases.${databaseId}.collections.${collectionId}.documents.`
      )
    );

    if (documentEvent) {
      if (documentEvent.endsWith(".create")) {
        handleDocumentCreated(payload);
      } else if (documentEvent.endsWith(".update")) {
        handleDocumentUpdated(payload);
      } else if (documentEvent.endsWith(".delete")) {
        handleDocumentDeleted(payload);
      }
      return;
    }

    // File upload = Storage file create event
    const fileEvent = events.find((event) =>
      event.startsWith(`buckets.${bucketId}.files.`)
    );

    if (fileEvent?.endsWith(".create")) {
      handleFileUploaded(payload);
    }
  }
);

// ---- handlers ----

function handleDocumentCreated(doc) {
  console.log("Document created:", doc);
  // e.g. add doc to UI
}

function handleDocumentUpdated(doc) {
  console.log("Document updated:", doc);
  // e.g. update doc in UI
}

function handleDocumentDeleted(doc) {
  console.log("Document deleted:", doc);
  // e.g. remove doc from UI
}

function handleFileUploaded(file) {
  console.log("File uploaded:", file);
  // e.g. show thumbnail / refresh file list
}

// Later, when you want to stop listening:
// unsubscribe();
```

Notes:
- In Appwrite Storage, a completed upload appears as a `.create` realtime event on `buckets.<bucketId>.files`.
- The current user/session must have permission to read those documents/files, or no realtime events will arrive.

Here’s a Web SDK example for the current Appwrite JS API.

> Note: creating databases, collections, and attributes is a privileged action. This code assumes the current session is already authenticated as a project member/admin. In production, do schema setup from a server or Appwrite Function, not public frontend code.

```js
import { Client, Databases, ID } from "appwrite";

const client = new Client()
  .setEndpoint("https://<APPWRITE_ENDPOINT>/v1")
  .setProject("<PROJECT_ID>");
// .setSelfSigned(true); // Uncomment for local self-hosted development

const databases = new Databases(client);

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

async function waitForAttributes(databaseId, collectionId, keys) {
  while (true) {
    const result = await databases.listAttributes({
      databaseId,
      collectionId,
    });

    const attrs = keys.map((key) =>
      result.attributes.find((attr) => attr.key === key)
    );

    const failed = attrs.find((attr) => attr?.status === "failed");
    if (failed) {
      throw new Error(`Attribute "${failed.key}" failed to create.`);
    }

    const allReady = attrs.every((attr) => attr?.status === "available");
    if (allReady) return;

    await sleep(1000);
  }
}

async function setupTasksExample() {
  // 1) Create a database
  const database = await databases.create({
    databaseId: ID.unique(),
    name: "Tasks DB",
    enabled: true,
  });

  // 2) Create the "tasks" collection
  const collection = await databases.createCollection({
    databaseId: database.$id,
    collectionId: "tasks",
    name: "Tasks",
    permissions: [], // Add collection permissions for your app as needed
    documentSecurity: false,
    enabled: true,
  });

  // 3) Create attributes
  await databases.createStringAttribute({
    databaseId: database.$id,
    collectionId: collection.$id,
    key: "title",
    size: 255,
    required: true,
  });

  await databases.createBooleanAttribute({
    databaseId: database.$id,
    collectionId: collection.$id,
    key: "completed",
    required: true,
  });

  await databases.createDatetimeAttribute({
    databaseId: database.$id,
    collectionId: collection.$id,
    key: "dueDate",
    required: true,
  });

  // Attribute creation is async in Appwrite, so wait until they're available
  await waitForAttributes(database.$id, collection.$id, [
    "title",
    "completed",
    "dueDate",
  ]);

  // 4) Insert a document
  const document = await databases.createDocument({
    databaseId: database.$id,
    collectionId: collection.$id,
    documentId: ID.unique(),
    data: {
      title: "Finish Appwrite setup",
      completed: false,
      dueDate: new Date("2026-03-20T12:00:00Z").toISOString(),
    },
  });

  console.log("Database:", database);
  console.log("Collection:", collection);
  console.log("Document:", document);
}

setupTasksExample().catch(console.error);
```

A couple of important details:
- `dueDate` should be an ISO 8601 string.
- Attribute creation is asynchronous, so waiting before inserting the first document is important.

If you want, I can also give you the same example using the Node SDK, which is usually better for schema creation.

