Bucket creation is an admin operation in Appwrite, so do that step with a **Server SDK** or an **Appwrite Function**. Then use the **Web SDK** in the browser to upload the image and get its preview URL.

### 1) Create the bucket once (server-side)

```js
// setup-bucket.js
import { Client, Storage, Permission, Role } from "node-appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>")
  .setKey("<API_KEY>");

const storage = new Storage(client);

await storage.createBucket(
  "images", // bucketId
  "Images", // name
  [
    Permission.create(Role.users()), // signed-in users can upload
    // Optional if you want client-side bucket/file listing:
    // Permission.read(Role.users()),
    // Optional bucket management permissions:
    // Permission.update(Role.team("<ADMIN_TEAM_ID>")),
    // Permission.delete(Role.team("<ADMIN_TEAM_ID>")),
  ],
  true,                  // fileSecurity: enables per-file permissions
  true,                  // enabled
  10 * 1024 * 1024,      // max file size: 10 MB
  ["jpg", "jpeg", "png", "webp", "gif"]
);

console.log("Bucket created");
```

---

### 2) Upload an image and get a preview URL (Web SDK)

```html
<input id="imageInput" type="file" accept="image/*" />
<img id="preview" alt="Uploaded image preview" />
```

```js
// browser.js
import { Client, Account, Storage, ID, Permission, Role } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1")
  .setProject("<PROJECT_ID>");

const account = new Account(client);
const storage = new Storage(client);

async function uploadImageAndGetPreview(file) {
  if (!file || !file.type.startsWith("image/")) {
    throw new Error("Please select an image file.");
  }

  // Assumes the user is already signed in
  const user = await account.get();

  const uploadedFile = await storage.createFile(
    "images",
    ID.unique(),
    file,
    [
      Permission.read(Role.any()),            // public preview/view
      Permission.write(Role.user(user.$id)),  // uploader can update/delete
    ]
  );

  const previewUrl = storage
    .getFilePreview("images", uploadedFile.$id, 800, 800)
    .toString();

  return { uploadedFile, previewUrl };
}

document.getElementById("imageInput").addEventListener("change", async (event) => {
  try {
    const file = event.target.files[0];
    const { previewUrl } = await uploadImageAndGetPreview(file);

    document.getElementById("preview").src = previewUrl;
    console.log("Preview URL:", previewUrl);
  } catch (error) {
    console.error(error);
  }
});
```

### Notes
- `fileSecurity: true` is important. Without it, the file permissions you pass to `createFile()` won’t be used.
- `Permission.read(Role.any())` makes the image preview public.
- If you want the file to stay private, change that to:

```js
Permission.read(Role.user(user.$id))
```

If you want, I can also show the same example using an **Appwrite Function** for bucket creation instead of `node-appwrite`.

# Email/Password Auth with Appwrite Web SDK

## 1. Install the SDK

```bash
npm install appwrite
```

## 2. Set Up the Client

```javascript
import { Client, Account, ID } from 'appwrite';

const client = new Client();

client
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your Project ID

const account = new Account(client);
```

## 3. Sign Up (Create a New Account)

```javascript
async function signup(email, password, name) {
    try {
        const newAccount = await account.create(
            ID.unique(),  // userId - auto-generate a unique ID
            email,
            password,     // Must be at least 8 characters
            name          // Optional: user's name
        );
        console.log('Account created:', newAccount);
        return newAccount;
    } catch (error) {
        console.error('Signup failed:', error.message);
        throw error;
    }
}
```

## 4. Log In (Create an Email Session)

```javascript
async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(email, password);
        console.log('Session created:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error.message);
        throw error;
    }
}
```

## 5. Get Current User (Verify Session)

```javascript
async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        console.error('Not authenticated:', error.message);
        return null;
    }
}
```

## 6. Log Out (Delete Session)

```javascript
async function logout() {
    try {
        await account.deleteSession('current'); // Deletes the current session
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout failed:', error.message);
        throw error;
    }
}
```

## Full Usage Example

```javascript
// Sign up a new user
await signup('user@example.com', 'securePassword123', 'John Doe');

// Log in with the new account
await login('user@example.com', 'securePassword123');

// Verify the session by fetching the current user
const user = await getCurrentUser();
console.log(`Logged in as: ${user.name} (${user.email})`);

// Log out when done
await logout();
```

## Key Notes

- **Password requirements**: Minimum 8 characters, maximum 256 characters.
- **`ID.unique()`**: Tells Appwrite to auto-generate a unique user ID. You can also pass a custom string (up to 36 characters).
- **Session management**: Appwrite uses **httpOnly cookies** in the browser to persist sessions automatically — no need to manually store tokens.
- **Sign up does NOT create a session** — you must call `login()` after `signup()` to authenticate the user.
- **`createEmailPasswordSession`** replaced the older `createEmailSession` method in newer SDK versions.

# `account.deleteSession()` vs `account.deleteSessions()`

## `account.deleteSession(sessionId)`

**Deletes a single, specific session.**

```javascript
// Log out from the current session only
await account.deleteSession('current');

// Log out a specific session by its ID
await account.deleteSession('507f1f77bcf86cd799439011');
```

**When to use:**
- **Logging out the current user** from the current device (pass `'current'` as the session ID)
- **Revoking a specific session**, e.g., the user sees a list of active sessions and wants to remove one they don't recognize
- Standard "Log Out" button functionality

---

## `account.deleteSessions()`

**Deletes ALL active sessions for the current user.**

```javascript
// Log out from every device/session at once
await account.deleteSessions();
```

**When to use:**
- **"Log out of all devices"** feature (like Google/Netflix offer)
- **Security response** — if an account is compromised, nuke all sessions so the attacker loses access everywhere
- **Password reset/change flows** — after a user changes their password, you may want to invalidate all existing sessions
- **Account deactivation** workflows

---

## Key Differences at a Glance

| | `deleteSession(sessionId)` | `deleteSessions()` |
|---|---|---|
| **Scope** | Single session | All sessions |
| **Parameter** | Session ID or `'current'` | None |
| **Typical use** | Standard logout | "Log out everywhere" |
| **Impact** | Minimal — other sessions stay active | Full — user is signed out on every device |

---

## Practical Example

```javascript
// Standard logout button
async function logout() {
  await account.deleteSession('current');
}

// "Sign out everywhere" security option
async function logoutAllDevices() {
  await account.deleteSessions();
}
```

> **Tip:** In most apps, your default logout action should use `deleteSession('current')` so users aren't unexpectedly logged out on other devices. Reserve `deleteSessions()` for explicit security actions.

# Querying Documents in Appwrite with the Query Class

Appwrite's `Query` class provides a fluent, expressive way to filter, sort, and paginate documents from your database collections.

## Basic Setup

```javascript
import { Client, Databases, Query } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

const databases = new Databases(client);
```

## Listing Documents with Queries

All queries are passed as an array to the `queries` parameter of `listDocuments`:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        // queries go here
    ]
);
```

---

## 1. Filtering

### Equality & Inequality
```javascript
// Exact match
Query.equal('status', 'active')

// Not equal
Query.notEqual('status', 'archived')

// Match any value in array
Query.equal('category', ['science', 'tech', 'art'])
```

### Comparison Operators
```javascript
// Greater than / Greater than or equal
Query.greaterThan('price', 100)
Query.greaterThanEqual('price', 100)

// Less than / Less than or equal
Query.lessThan('price', 500)
Query.lessThanEqual('price', 500)

// Between (inclusive)
Query.between('price', 100, 500)
```

### String Searches
```javascript
// Starts with
Query.startsWith('name', 'John')

// Ends with
Query.endsWith('email', '@gmail.com')

// Contains (requires a fulltext index)
Query.contains('tags', ['javascript'])

// Search (requires a fulltext index)
Query.search('content', 'appwrite tutorial')
```

### Null Checks
```javascript
Query.isNull('deletedAt')
Query.isNotNull('verifiedAt')
```

---

## 2. Sorting

```javascript
// Ascending order
Query.orderAsc('createdAt')

// Descending order
Query.orderDesc('price')
```

You can combine multiple sort orders:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.orderDesc('priority'),
        Query.orderAsc('title')
    ]
);
```

---

## 3. Limiting Results

```javascript
// Return only 10 documents
Query.limit(10)

// Skip the first 20 documents (offset)
Query.offset(20)
```

---

## 4. Pagination

### Offset-Based Pagination

```javascript
const page = 2;
const perPage = 25;

const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.limit(perPage),
        Query.offset((page - 1) * perPage),
        Query.orderDesc('$createdAt')
    ]
);
// response.total  → total number of matching documents
// response.documents → array of documents for this page
```

> **Note:** Offset pagination can be slow for large datasets because the database must scan and skip rows.

### Cursor-Based Pagination (Recommended for Large Datasets)

Use `cursorAfter` or `cursorBefore` with the `$id` of the last/first document from the previous page:

```javascript
// First page
const firstPage = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.limit(25),
        Query.orderDesc('$createdAt')
    ]
);

// Next page — pass the last document's ID
const lastDocId = firstPage.documents[firstPage.documents.length - 1].$id;

const secondPage = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.limit(25),
        Query.orderDesc('$createdAt'),
        Query.cursorAfter(lastDocId)
    ]
);

// Previous page — pass the first document's ID
const firstDocId = secondPage.documents[0].$id;

const previousPage = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.limit(25),
        Query.orderDesc('$createdAt'),
        Query.cursorBefore(firstDocId)
    ]
);
```

---

## 5. Selecting Specific Attributes

Reduce payload size by requesting only the fields you need:

```javascript
Query.select(['title', 'price', '$id', '$createdAt'])
```

---

## 6. Combined Example

A real-world query combining multiple operations:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        // Filters
        Query.equal('status', 'published'),
        Query.greaterThan('price', 10),
        Query.lessThanEqual('price', 200),
        Query.isNotNull('imageUrl'),

        // Select specific fields
        Query.select(['title', 'price', 'status', '$id', '$createdAt']),

        // Sort
        Query.orderDesc('$createdAt'),

        // Pagination
        Query.limit(25),
        Query.offset(0)
    ]
);

console.log(`Total matching: ${response.total}`);
console.log(`Returned: ${response.documents.length}`);
response.documents.forEach(doc => {
    console.log(`${doc.title} — $${doc.price}`);
});
```

---

## Or Queries

By default, multiple filters are combined with **AND** logic. To use **OR** logic, wrap queries with `Query.or()`:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.or([
            Query.equal('status', 'featured'),
            Query.greaterThan('rating', 4.5)
        ])
    ]
);
```

---

## Key Considerations

| Consideration | Detail |
|---|---|
| **Indexes required** | Create indexes on attributes you filter/sort on; queries on unindexed attributes will fail |
| **Max queries** | Up to **100** queries per request |
| **Max limit** | Default and max `limit` is **5000** documents per request |
| **Offset cap** | Offset cannot exceed **5000**; use cursor pagination for deeper pages |
| **Supported types** | Queries work on `string`, `integer`, `float`, `boolean`, `datetime`, and `enum` attribute types |

# Appwrite: Create Database, Collection, Attributes & Document

> **Important:** Creating databases, collections, and attributes are **admin operations** that require a server SDK with an API key. Document creation can be done from either SDK. The example below covers both.

## Step 1: Server-Side Setup (Node SDK)

```javascript
import { Client, Databases, ID, Permission, Role } from 'node-appwrite';

// Initialize the server client with an API key
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID')
    .setKey('YOUR_API_KEY'); // Requires databases.read & databases.write scopes

const databases = new Databases(client);

const DATABASE_ID = ID.unique();
const COLLECTION_ID = ID.unique();

async function setupDatabase() {
    // 1. Create the database
    const db = await databases.create(DATABASE_ID, 'TasksDB');
    console.log('Database created:', db.$id);

    // 2. Create the "tasks" collection with permissions
    const collection = await databases.createCollection(
        DATABASE_ID,
        COLLECTION_ID,
        'tasks',
        [
            Permission.read(Role.any()),
            Permission.create(Role.users()),
            Permission.update(Role.users()),
            Permission.delete(Role.users()),
        ]
    );
    console.log('Collection created:', collection.$id);

    // 3. Create attributes
    await databases.createStringAttribute(
        DATABASE_ID,
        COLLECTION_ID,
        'title',    // key
        255,        // size
        true        // required
    );

    await databases.createBooleanAttribute(
        DATABASE_ID,
        COLLECTION_ID,
        'completed', // key
        true,        // required
        false        // default value
    );

    await databases.createDatetimeAttribute(
        DATABASE_ID,
        COLLECTION_ID,
        'dueDate',  // key
        true         // required
    );

    // Attributes are created asynchronously — wait for processing
    console.log('Attributes created. Waiting for processing...');
    await waitForAttributes();

    // 4. Insert a document (server-side)
    const document = await databases.createDocument(
        DATABASE_ID,
        COLLECTION_ID,
        ID.unique(),
        {
            title: 'Finish Appwrite tutorial',
            completed: false,
            dueDate: new Date('2025-12-31T23:59:59.000+00:00').toISOString(),
        }
    );
    console.log('Document created:', document);
}

// Helper: poll until all attributes are "available"
async function waitForAttributes() {
    const maxRetries = 10;
    for (let i = 0; i < maxRetries; i++) {
        await new Promise((resolve) => setTimeout(resolve, 1500));

        const attrs = await databases.listAttributes(DATABASE_ID, COLLECTION_ID);
        const allReady = attrs.attributes.every(
            (attr) => attr.status === 'available'
        );

        if (allReady) {
            console.log('All attributes are available.');
            return;
        }
        console.log(`Retry ${i + 1}/${maxRetries} — attributes still processing...`);
    }
    throw new Error('Attributes did not become available in time.');
}

setupDatabase().catch(console.error);
```

## Step 2: Client-Side Document Creation (Web SDK)

Once the database and collection exist, use the **Web SDK** to insert documents from the browser:

```javascript
import { Client, Databases, ID } from 'appwrite';

// Initialize the client (no API key — uses session auth)
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID');

const databases = new Databases(client);

// Use the IDs from your setup step
const DATABASE_ID = 'YOUR_DATABASE_ID';
const COLLECTION_ID = 'YOUR_COLLECTION_ID';

async function createTask(title, dueDate, completed = false) {
    try {
        const document = await databases.createDocument(
            DATABASE_ID,
            COLLECTION_ID,
            ID.unique(),
            {
                title,
                completed,
                dueDate: new Date(dueDate).toISOString(),
            }
        );
        console.log('Task created:', document);
        return document;
    } catch (error) {
        console.error('Failed to create task:', error.message);
        throw error;
    }
}

// Usage — user must be authenticated
createTask('Buy groceries', '2025-08-15T18:00:00.000+00:00');
```

## Key Points

| Concern | Detail |
|---|---|
| **Admin operations** | `createDatabase`, `createCollection`, `create*Attribute` require the **server SDK** (`node-appwrite`) with an API key |
| **Attribute processing** | Attributes are created **asynchronously** — poll their `status` before inserting documents |
| **Datetime format** | Must be **ISO 8601** with timezone (e.g., `2025-12-31T23:59:59.000+00:00`) |
| **Permissions** | Set at the collection level (and optionally per-document) to control client-side access |
| **Client auth** | The Web SDK relies on **session-based auth** — the user must be logged in for document operations |

# Appwrite Function: Personalized Greeting

## Function Code (`src/main.js`)

```javascript
export default async ({ req, res, log, error }) => {
  // Only allow POST requests
  if (req.method !== 'POST') {
    return res.json(
      { ok: false, message: 'Method not allowed. Use POST.' },
      405
    );
  }

  // req.body is automatically parsed as an object when Content-Type is application/json
  const { name } = req.body;

  // Validate the "name" field
  if (!name || typeof name !== 'string') {
    error('Missing or invalid "name" field in request body.');
    return res.json(
      { ok: false, message: 'Please provide a valid "name" field in the JSON body.' },
      400
    );
  }

  log(`Generating greeting for: ${name}`);

  return res.json({
    ok: true,
    greeting: `Hello, ${name}! Welcome to Appwrite 👋`,
  });
};
```

## Example Request & Response

**Request:**
```bash
curl -X POST https://<APPWRITE_ENDPOINT>/functions/<FUNCTION_ID>/executions \
  -H "Content-Type: application/json" \
  -H "X-Appwrite-Project: <PROJECT_ID>" \
  -H "X-Appwrite-Key: <API_KEY>" \
  -d '{"body": "{\"name\": \"Alice\"}"}'
```

**Response (200):**
```json
{
  "ok": true,
  "greeting": "Hello, Alice! Welcome to Appwrite 👋"
}
```

**Error Response (400):**
```json
{
  "ok": false,
  "message": "Please provide a valid \"name\" field in the JSON body."
}
```

## Key Points

| Concept | Detail |
|---|---|
| **Function signature** | Destructure `{ req, res, log, error }` from the context object |
| **`req.body`** | Automatically parsed into an object when the request has `Content-Type: application/json` |
| **`res.json(body, statusCode)`** | Returns a JSON response with an optional HTTP status code (defaults to `200`) |
| **`log()` / `error()`** | Write to the function's execution logs (visible in the Appwrite Console) |
| **`req.method`** | The HTTP method (`GET`, `POST`, etc.) used to invoke the function |

> **Note:** Make sure your `package.json` includes `"type": "module"` to support the ES module `export default` syntax, which is the standard for Appwrite Node.js function starters.

# Appwrite Storage: Create Bucket, Upload File & Get Preview

## 1. Setup & Initialization

```javascript
import { Client, Storage, ID, Permission, Role, ImageGravity, ImageFormat } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your project ID

const storage = new Storage(client);
```

## 2. Create a Bucket (Server-Side with Node SDK)

> **Note:** Bucket creation requires an API key, so this is done server-side.

```javascript
import { Client, Storage, Permission, Role } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<YOUR_PROJECT_ID>')
    .setKey('<YOUR_API_KEY>');

const storage = new Storage(client);

async function createBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),               // Bucket ID (or use a custom string)
            'images',                  // Bucket name
            [
                Permission.read(Role.any()),          // Anyone can read/view
                Permission.create(Role.users()),      // Authenticated users can upload
                Permission.update(Role.users()),      // Authenticated users can update
                Permission.delete(Role.users()),      // Authenticated users can delete
            ],
            false,                     // fileSecurity - false uses bucket-level permissions
            true,                      // enabled
            30000000,                  // maximumFileSize (30MB in bytes)
            ['image/png', 'image/jpeg', 'image/gif', 'image/webp'], // allowedFileExtensions
            'gzip',                    // compression
            true,                      // encryption
            true                       // antivirus
        );

        console.log('Bucket created:', bucket);
        return bucket;
    } catch (error) {
        console.error('Error creating bucket:', error.message);
    }
}

createBucket();
```

## 3. Upload a File (Client-Side)

```javascript
const BUCKET_ID = '<YOUR_BUCKET_ID>';

async function uploadFile(file) {
    try {
        const response = await storage.createFile(
            BUCKET_ID,
            ID.unique(),         // File ID
            file,                // File object (from <input type="file">)
            [
                // File-level permissions (only used if fileSecurity is true on the bucket)
                Permission.read(Role.any()),
                Permission.update(Role.user('<USER_ID>')),
                Permission.delete(Role.user('<USER_ID>')),
            ]
        );

        console.log('File uploaded:', response);
        return response;
    } catch (error) {
        console.error('Upload failed:', error.message);
    }
}
```

## 4. Get a File Preview URL

```javascript
function getPreviewURL(fileId) {
    const result = storage.getFilePreview(
        BUCKET_ID,
        fileId,
        400,                    // width (px)
        300,                    // height (px)
        ImageGravity.Center,    // gravity/crop focus
        90,                     // quality (0-100)
        0,                      // borderWidth
        '',                     // borderColor
        0,                      // borderRadius
        1,                      // opacity (0-1)
        0,                      // rotation (-360 to 360)
        '',                     // background color (hex)
        ImageFormat.Webp        // output format
    );

    console.log('Preview URL:', result.href);
